INSERT INTO asana.asana_tasks (task_gid, name, assignee_gid, project_name, project_gid, section_name, due_on, start_on, completed, completed_at, routine_rw, priority_rw, importance_rw, kiro_rw, next_action_rw, begin_date_rw, flex_fields, synced_at) VALUES ('1213493347703132', 'MCS landing page optimization P1', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', '2026-03-31'::DATE, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "Phase One of the MCS Landing Page Optimization initiative officially launched in March 2026 with testing beginning in FR on 3/3 and expanding to EU4 in W11, following successful testing in Canada. This phase encompasses three key enhancements: the integration of localized, market-relevant verbiage within headline copy to better resonate with regional audiences; updates to the mobile experience and layout; and the implementation of current, on-brand visuals to ensure consistent brand presentation. The successful Canadian pilot validated the MCS optimizations made with an expected CVR lift of 50% in EU5 on tested LPs. Projected impact is included in OP2 registration, not additional. Results will be available EOM April due to OCI tech readiness data exclusions across EU3."}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103663": {"name": "Impact (EU Reg)", "value": "14000"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}, "1212629048694011": {"name": "Marketplace/Region", "value": "EU5"}}'::JSON, now()) ON CONFLICT (task_gid) DO UPDATE SET name=EXCLUDED.name, assignee_gid=EXCLUDED.assignee_gid, project_name=EXCLUDED.project_name, project_gid=EXCLUDED.project_gid, section_name=EXCLUDED.section_name, due_on=EXCLUDED.due_on, start_on=EXCLUDED.start_on, completed=EXCLUDED.completed, completed_at=EXCLUDED.completed_at, routine_rw=EXCLUDED.routine_rw, priority_rw=EXCLUDED.priority_rw, importance_rw=EXCLUDED.importance_rw, kiro_rw=EXCLUDED.kiro_rw, next_action_rw=EXCLUDED.next_action_rw, begin_date_rw=EXCLUDED.begin_date_rw, flex_fields=EXCLUDED.flex_fields, deleted_at=NULL, synced_at=now();
INSERT INTO asana.asana_tasks (task_gid, name, assignee_gid, project_name, project_gid, section_name, due_on, start_on, completed, completed_at, routine_rw, priority_rw, importance_rw, kiro_rw, next_action_rw, begin_date_rw, flex_fields, synced_at) VALUES ('1212832868560339', 'Portfolio Consolidation', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', '2026-06-30'::DATE, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"1211898465243458": {"name": "Status C-week", "value": "Not Started"}, "1209637014993158": {"name": "Notes - Task", "value": "In alignment with Google\ufffd\ufffd\ufffds best practices and smart bidding protocols, we will consolidate split portfolios into a more cohesive structure, with the objective of enhancing signal quality for Google\ufffd\ufffd\ufffds algorithms and ensuring alignment with smart bidding optimization best practices. \n\nThe team plans to test this approach in Q1 by combining two portfolios into one in the DE market.\n\n"}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}}'::JSON, now()) ON CONFLICT (task_gid) DO UPDATE SET name=EXCLUDED.name, assignee_gid=EXCLUDED.assignee_gid, project_name=EXCLUDED.project_name, project_gid=EXCLUDED.project_gid, section_name=EXCLUDED.section_name, due_on=EXCLUDED.due_on, start_on=EXCLUDED.start_on, completed=EXCLUDED.completed, completed_at=EXCLUDED.completed_at, routine_rw=EXCLUDED.routine_rw, priority_rw=EXCLUDED.priority_rw, importance_rw=EXCLUDED.importance_rw, kiro_rw=EXCLUDED.kiro_rw, next_action_rw=EXCLUDED.next_action_rw, begin_date_rw=EXCLUDED.begin_date_rw, flex_fields=EXCLUDED.flex_fields, deleted_at=NULL, synced_at=now();
INSERT INTO asana.asana_tasks (task_gid, name, assignee_gid, project_name, project_gid, section_name, due_on, start_on, completed, completed_at, routine_rw, priority_rw, importance_rw, kiro_rw, next_action_rw, begin_date_rw, flex_fields, synced_at) VALUES ('1212832868560333', 'AMO Objective Change Test', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', '2026-04-30'::DATE, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "The implementation was initiated for a subset of IT portfolios on 1/5, with the remaining portfolios migrated on 1/15. Following the implementation of the new feed, data discrepancies between our dashboard and AMO decreased from -23% to +6% avg in IT, significantly improving reporting accuracy and insight quality. While the bidding objective change in IT has not yet driven incremental lift, the enhanced data reliability positions us well for more informed optimization decisions. We have also transitioned our reporting to align with the new registrations objective (and transitioned the portfolios currently using Daily spend target to the new objectives in EU2 on 3/3/26). Data will continue to inform optimizations post OCI implementation."}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103663": {"name": "Impact (EU Reg)", "value": "0"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}}'::JSON, now()) ON CONFLICT (task_gid) DO UPDATE SET name=EXCLUDED.name, assignee_gid=EXCLUDED.assignee_gid, project_name=EXCLUDED.project_name, project_gid=EXCLUDED.project_gid, section_name=EXCLUDED.section_name, due_on=EXCLUDED.due_on, start_on=EXCLUDED.start_on, completed=EXCLUDED.completed, completed_at=EXCLUDED.completed_at, routine_rw=EXCLUDED.routine_rw, priority_rw=EXCLUDED.priority_rw, importance_rw=EXCLUDED.importance_rw, kiro_rw=EXCLUDED.kiro_rw, next_action_rw=EXCLUDED.next_action_rw, begin_date_rw=EXCLUDED.begin_date_rw, flex_fields=EXCLUDED.flex_fields, deleted_at=NULL, synced_at=now();
INSERT INTO asana.asana_tasks (task_gid, name, assignee_gid, project_name, project_gid, section_name, due_on, start_on, completed, completed_at, routine_rw, priority_rw, importance_rw, kiro_rw, next_action_rw, begin_date_rw, flex_fields, synced_at) VALUES ('1212832868339127', 'Evidence Based Ad Copy Test', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', '2026-12-31'::DATE, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "Evidence-based ad copy testing is currently underway in the UK (launched 1/29) and IT (launched 2/19). We anticipate an increase in click-through rates, alongside an incremental rise in registrations, with a before and after lift of 85 regs in initial UK results and +3% CVR lift and improved CTR (15% control vs 28% test). In IT was saw a 15% lift in CTR. Due to success we rolled out Phase 2 in UK and IT (100% of NB) ahead of schedule, with phased rollouts scheduled across the EU in Q3 and Q4 2026 - post OCI implementation. Projected registration impact is included in OCI reg projections and not incremental lift.\n"}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103663": {"name": "Impact (EU Reg)", "value": "2000"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}, "1212629048694011": {"name": "Marketplace/Region", "value": "EU5"}}'::JSON, now()) ON CONFLICT (task_gid) DO UPDATE SET name=EXCLUDED.name, assignee_gid=EXCLUDED.assignee_gid, project_name=EXCLUDED.project_name, project_gid=EXCLUDED.project_gid, section_name=EXCLUDED.section_name, due_on=EXCLUDED.due_on, start_on=EXCLUDED.start_on, completed=EXCLUDED.completed, completed_at=EXCLUDED.completed_at, routine_rw=EXCLUDED.routine_rw, priority_rw=EXCLUDED.priority_rw, importance_rw=EXCLUDED.importance_rw, kiro_rw=EXCLUDED.kiro_rw, next_action_rw=EXCLUDED.next_action_rw, begin_date_rw=EXCLUDED.begin_date_rw, flex_fields=EXCLUDED.flex_fields, deleted_at=NULL, synced_at=now();
INSERT INTO asana.asana_tasks (task_gid, name, assignee_gid, project_name, project_gid, section_name, due_on, start_on, completed, completed_at, routine_rw, priority_rw, importance_rw, kiro_rw, next_action_rw, begin_date_rw, flex_fields, synced_at) VALUES ('1212832868339125', 'Campaign Consolidation', '1210930052337043', 'ABPS - WW Testing & Projects', '1205997667578893', 'Paid Search', '2026-12-31'::DATE, NULL, FALSE, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '{"1211898465243458": {"name": "Status C-week", "value": "Green - On track"}, "1209637014993158": {"name": "Notes - Task", "value": "Account consolidation is underway in OCI regions, with EU3 slated for August after OCI implementation is complete. \n\nUK and DE Product and Vertical campaigns have been consolidated in January 2026 to streamline the account and reduce management overhead."}, "1211898253103683": {"name": "Help Needed flag", "value": "No"}, "1211898253103687": {"name": "Status L-week", "value": "Green - On track"}, "1212629048694011": {"name": "Marketplace/Region", "value": "EU5"}}'::JSON, now()) ON CONFLICT (task_gid) DO UPDATE SET name=EXCLUDED.name, assignee_gid=EXCLUDED.assignee_gid, project_name=EXCLUDED.project_name, project_gid=EXCLUDED.project_gid, section_name=EXCLUDED.section_name, due_on=EXCLUDED.due_on, start_on=EXCLUDED.start_on, completed=EXCLUDED.completed, completed_at=EXCLUDED.completed_at, routine_rw=EXCLUDED.routine_rw, priority_rw=EXCLUDED.priority_rw, importance_rw=EXCLUDED.importance_rw, kiro_rw=EXCLUDED.kiro_rw, next_action_rw=EXCLUDED.next_action_rw, begin_date_rw=EXCLUDED.begin_date_rw, flex_fields=EXCLUDED.flex_fields, deleted_at=NULL, synced_at=now();
